// Advanced spam detection algorithm
const formData = $input.item.json;
let spamScore = 0;
const spamReasons = [];

// Check 1: Honeypot field (should be empty)
if (formData.honeypot_field && formData.honeypot_field.length > 0) {
  spamScore += 100;
  spamReasons.push('Honeypot field filled');
}

// Check 2: Submission time (too fast = bot)
const submissionTime = formData.form_interaction_time || 0; // milliseconds
if (submissionTime < 3000) { // Less than 3 seconds
  spamScore += 50;
  spamReasons.push(`Submitted too quickly (${submissionTime}ms)`);
} else if (submissionTime < 5000) {
  spamScore += 25;
  spamReasons.push(`Fast submission (${submissionTime}ms)`);
}

// Check 3: Email domain validation
const email = formData.email || '';
const disposableEmailDomains = [
  'tempmail.com', 'guerrillamail.com', '10minutemail.com', 'mailinator.com',
  'throwaway.email', 'trashmail.com', 'yopmail.com', 'maildrop.cc'
];

const emailDomain = email.split('@')[1]?.toLowerCase();
if (disposableEmailDomains.includes(emailDomain)) {
  spamScore += 40;
  spamReasons.push(`Disposable email domain: ${emailDomain}`);
}

// Check 4: Email format validation
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email)) {
  spamScore += 30;
  spamReasons.push('Invalid email format');
}

// Check 5: Message quality analysis
const message = formData.message || '';

// Too short
if (message.length < 10) {
  spamScore += 30;
  spamReasons.push(`Message too short (${message.length} chars)`);
}

// Excessive links
const linkCount = (message.match(/http(s)?:\/\//g) || []).length;
if (linkCount > 3) {
  spamScore += 40;
  spamReasons.push(`Too many links (${linkCount})`);
} else if (linkCount > 1) {
  spamScore += 20;
  spamReasons.push(`Multiple links (${linkCount})`);
}

// Suspicious keywords
const spamKeywords = [
  'viagra', 'cialis', 'lottery', 'winner', 'prince', 'inheritance',
  'casino', 'bitcoin', 'crypto', 'investment opportunity', 'click here',
  'buy now', 'limited time', 'act now', 'congratulations', 'you have won'
];

const lowercaseMessage = message.toLowerCase();
const foundKeywords = spamKeywords.filter(keyword => lowercaseMessage.includes(keyword));
if (foundKeywords.length > 0) {
  spamScore += foundKeywords.length * 20;
  spamReasons.push(`Spam keywords: ${foundKeywords.join(', ')}`);
}

// Check 6: Excessive capitalization
const capsRatio = (message.match(/[A-Z]/g) || []).length / message.length;
if (capsRatio > 0.5 && message.length > 20) {
  spamScore += 25;
  spamReasons.push(`Excessive capitals (${Math.round(capsRatio * 100)}%)`);
}

// Check 7: Repeated characters (e.g., "hellooooo")
if (/(.)\1{4,}/.test(message)) {
  spamScore += 15;
  spamReasons.push('Excessive repeated characters');
}

// Check 8: Phone number validation (if provided)
const phone = formData.phone || '';
if (phone && !/^[\d\s\-\+\(\)]+$/.test(phone)) {
  spamScore += 20;
  spamReasons.push('Invalid phone number format');
}

// Check 9: Name validation
const firstName = formData.firstName || formData.first_name || '';
const lastName = formData.lastName || formData.last_name || '';

if (firstName.length < 2 || lastName.length < 2) {
  spamScore += 15;
  spamReasons.push('Suspiciously short name');
}

// Check for keyboard mashing (e.g., "asdfghjkl")
const keyboardPatterns = ['qwerty', 'asdfgh', 'zxcvbn', '123456', 'abcdef'];
const fullName = `${firstName} ${lastName}`.toLowerCase();
if (keyboardPatterns.some(pattern => fullName.includes(pattern))) {
  spamScore += 30;
  spamReasons.push('Keyboard pattern in name');
}

// Check 10: User agent validation
const userAgent = formData.user_agent || '';
if (!userAgent || userAgent.length < 20) {
  spamScore += 25;
  spamReasons.push('Missing or suspicious user agent');
}

// Check 11: Same field repetition
if (firstName === lastName || email.includes(firstName.toLowerCase())) {
  spamScore += 15;
  spamReasons.push('Repetitive field values');
}

// Determine spam classification
let classification = 'legitimate';
let action = 'accept';

if (spamScore >= 100) {
  classification = 'definite_spam';
  action = 'reject';
} else if (spamScore >= 60) {
  classification = 'likely_spam';
  action = 'quarantine';
} else if (spamScore >= 30) {
  classification = 'suspicious';
  action = 'review';
}

return {
  json: {
    // Original form data
    email: email,
    first_name: firstName,
    last_name: lastName,
    phone: phone,
    company: formData.company || '',
    message: message,

    // Spam analysis
    spam_score: spamScore,
    classification: classification,
    action: action,
    spam_reasons: spamReasons,
    checks_performed: 11,

    // Metadata
    submission_time: submissionTime,
    email_domain: emailDomain,
    link_count: linkCount,
    user_agent: userAgent,
    timestamp: new Date().toISOString()
  }
};

// Check rate limiting from Redis
const spamData = $('Code: Spam Detection Analysis').item.json;
const redisData = $input.item.json;

let submissionCount = 0;
let isRateLimited = false;

if (redisData && redisData.value) {
  try {
    const data = JSON.parse(redisData.value);
    submissionCount = data.count || 0;

    // Rate limit: max 3 submissions per email per hour
    if (submissionCount >= 3) {
      isRateLimited = true;
    }
  } catch (e) {
    // Redis data not parseable, assume first submission
  }
}

// Increment count
submissionCount++;

// Update spam score if rate limited
let finalSpamScore = spamData.spam_score;
let finalClassification = spamData.classification;
let finalAction = spamData.action;
const spamReasons = [...spamData.spam_reasons];

if (isRateLimited) {
  finalSpamScore += 50;
  spamReasons.push(`Rate limit exceeded (${submissionCount} submissions)`);

  if (finalSpamScore >= 100) {
    finalClassification = 'definite_spam';
    finalAction = 'reject';
  } else if (finalSpamScore >= 60) {
    finalClassification = 'likely_spam';
    finalAction = 'quarantine';
  }
}

return {
  json: {
    ...spamData,
    spam_score: finalSpamScore,
    classification: finalClassification,
    action: finalAction,
    spam_reasons: spamReasons,
    submission_count: submissionCount,
    is_rate_limited: isRateLimited
  }
};

